"use client";

/**
 * ActivityFeed Component
 *
 * A timeline of events and activities for SaaS dashboards.
 * Optimized for Product Mode with efficient scanning and clear hierarchy.
 *
 * @example
 * ```tsx
 * <ActivityFeed
 *   activities={[
 *     {
 *       id: '1',
 *       type: 'comment',
 *       actor: { name: 'John Doe' },
 *       title: 'Commented on Project X',
 *       relativeTime: '2 hours ago'
 *     }
 *   ]}
 * />
 * ```
 */

import { forwardRef } from "react";
import {
  MessageSquare,
  Edit,
  Plus,
  Trash2,
  UserPlus,
  CheckCircle,
  Upload,
  Circle,
} from "lucide-react";
import { Chip } from "../../components/Chip";
import { Button } from "../../components/Button";
import type { ActivityFeedProps, ActivityItem } from "./ActivityFeed.types";
import styles from "./ActivityFeed.module.css";

// Icon size constant (matches --size-icon-sm: 16px)
const ICON_SIZE = 16;

// Type to icon mapping
const typeIcons: Record<string, React.ReactNode> = {
  comment: <MessageSquare size={ICON_SIZE} />,
  update: <Edit size={ICON_SIZE} />,
  create: <Plus size={ICON_SIZE} />,
  delete: <Trash2 size={ICON_SIZE} />,
  assign: <UserPlus size={ICON_SIZE} />,
  complete: <CheckCircle size={ICON_SIZE} />,
  upload: <Upload size={ICON_SIZE} />,
  default: <Circle size={ICON_SIZE} />,
};

// Activity item component
const ActivityItemComponent = ({
  item,
  showConnector,
  compact,
}: {
  item: ActivityItem;
  showConnector: boolean;
  compact: boolean;
}) => {
  const icon = item.icon || typeIcons[item.type || "default"];
  const iconVariant = item.iconVariant || "default";

  return (
    <div className={`${styles.item} ${compact ? styles.itemCompact : ""}`}>
      <div className={styles.iconColumn}>
        <div
          className={`${styles.iconWrapper} ${styles[`iconVariant-${iconVariant}`]}`}
        >
          {icon}
        </div>
        {showConnector && <div className={styles.connector} />}
      </div>

      <div className={styles.content}>
        <div className={styles.header}>
          {item.actor && (
            <span className={styles.actor}>
              {item.actor.avatar && (
                <img
                  src={item.actor.avatar}
                  alt={item.actor.name}
                  className={styles.avatar}
                />
              )}
              {item.actor.href ? (
                <a href={item.actor.href} className={styles.actorName}>
                  {item.actor.name}
                </a>
              ) : (
                <span className={styles.actorName}>{item.actor.name}</span>
              )}
            </span>
          )}
          <span className={styles.title}>{item.title}</span>
          <span className={styles.time}>
            {item.relativeTime || item.timestamp}
          </span>
        </div>

        {item.description && (
          <div className={styles.description}>{item.description}</div>
        )}

        {item.metadata && Object.keys(item.metadata).length > 0 && (
          <div className={styles.metadata}>
            {Object.entries(item.metadata).map(([key, value]) => (
              <span key={key} className={styles.metadataItem}>
                <span className={styles.metadataKey}>{key}:</span>
                <span className={styles.metadataValue}>{value}</span>
              </span>
            ))}
          </div>
        )}

        {item.actions && <div className={styles.actions}>{item.actions}</div>}
      </div>
    </div>
  );
};

export const ActivityFeed = forwardRef<HTMLDivElement, ActivityFeedProps>(
  (
    {
      activities,
      showFilters = false,
      filters,
      activeFilter,
      onFilterChange,
      onLoadMore,
      hasMore = false,
      loading = false,
      emptyMessage = "No activity yet.",
      showConnectors = true,
      compact = false,
      className,
      ...rest
    },
    ref,
  ) => {
    const classNames = [
      styles.activityFeed,
      compact && styles.compact,
      className,
    ]
      .filter(Boolean)
      .join(" ");

    return (
      <div ref={ref} className={classNames} {...rest}>
        {/* Filters */}
        {showFilters && filters && filters.length > 0 && (
          <div className={styles.filters}>
            {filters.map((filter) => (
              <Chip
                key={filter.value}
                clickable
                selected={activeFilter === filter.value}
                onClick={() => onFilterChange?.(filter.value)}
              >
                {filter.label}
                {filter.count !== undefined && ` (${filter.count})`}
              </Chip>
            ))}
          </div>
        )}

        {/* Activity list */}
        <div className={styles.list}>
          {activities.length === 0 && !loading ? (
            <div className={styles.empty}>{emptyMessage}</div>
          ) : (
            activities.map((activity, index) => (
              <ActivityItemComponent
                key={activity.id}
                item={activity}
                showConnector={showConnectors && index < activities.length - 1}
                compact={compact}
              />
            ))
          )}

          {/* Loading skeleton */}
          {loading && (
            <>
              {[1, 2, 3].map((i) => (
                <div key={i} className={styles.skeleton}>
                  <div className={styles.skeletonIcon} />
                  <div className={styles.skeletonContent}>
                    <div className={styles.skeletonTitle} />
                    <div className={styles.skeletonDesc} />
                  </div>
                </div>
              ))}
            </>
          )}
        </div>

        {/* Load more */}
        {hasMore && !loading && (
          <Button
            variant="secondary"
            onClick={onLoadMore}
            style={{ width: "100%", marginTop: "var(--spacing-2)" }}
          >
            Load more
          </Button>
        )}
      </div>
    );
  },
);

ActivityFeed.displayName = "ActivityFeed";

/**
 * ActivityFeed Component Types
 *
 * Type definitions for the Orion ActivityFeed section component.
 * A timeline of events and activities for SaaS dashboards.
 */

import type { HTMLAttributes, ReactNode } from "react";

/**
 * Activity item actor (who performed the action)
 */
export interface ActivityActor {
  /**
   * Actor name
   */
  name: string;

  /**
   * Avatar URL
   */
  avatar?: string;

  /**
   * Link to actor profile
   */
  href?: string;
}

/**
 * Activity item for the feed
 */
export interface ActivityItem {
  /**
   * Unique identifier
   */
  id: string;

  /**
   * Activity type for icon selection
   */
  type?:
    | "comment"
    | "update"
    | "create"
    | "delete"
    | "assign"
    | "complete"
    | "upload"
    | "default";

  /**
   * Custom icon (overrides type-based icon)
   */
  icon?: ReactNode;

  /**
   * Icon background color variant
   */
  iconVariant?: "default" | "success" | "warning" | "error" | "info" | "brand";

  /**
   * Actor who performed the action
   */
  actor?: ActivityActor;

  /**
   * Activity title/summary
   */
  title: ReactNode;

  /**
   * Activity description/content
   */
  description?: ReactNode;

  /**
   * Timestamp
   */
  timestamp: string;

  /**
   * Relative time (e.g., "2 hours ago")
   */
  relativeTime?: string;

  /**
   * Associated metadata
   */
  metadata?: Record<string, ReactNode>;

  /**
   * Action buttons
   */
  actions?: ReactNode;
}

/**
 * ActivityFeed filter option
 */
export interface ActivityFilter {
  /**
   * Filter value
   */
  value: string;

  /**
   * Filter label
   */
  label: string;

  /**
   * Item count for this filter
   */
  count?: number;
}

/**
 * ActivityFeed section props
 *
 * @example
 * ```tsx
 * <ActivityFeed
 *   activities={[
 *     {
 *       id: '1',
 *       type: 'comment',
 *       actor: { name: 'John Doe', avatar: '/avatars/john.jpg' },
 *       title: 'Commented on Project X',
 *       description: 'Great progress on the design!',
 *       timestamp: '2024-01-15T10:30:00Z',
 *       relativeTime: '2 hours ago'
 *     }
 *   ]}
 * />
 * ```
 */
export interface ActivityFeedProps extends HTMLAttributes<HTMLDivElement> {
  /**
   * Array of activity items
   */
  activities: ActivityItem[];

  /**
   * Show filter controls
   * @default false
   */
  showFilters?: boolean;

  /**
   * Filter options
   */
  filters?: ActivityFilter[];

  /**
   * Current filter value
   */
  activeFilter?: string;

  /**
   * Filter change handler
   */
  onFilterChange?: (filter: string) => void;

  /**
   * Load more callback
   */
  onLoadMore?: () => void;

  /**
   * Whether more items are available
   */
  hasMore?: boolean;

  /**
   * Loading state
   */
  loading?: boolean;

  /**
   * Empty state message
   */
  emptyMessage?: string;

  /**
   * Show connector lines between items
   * @default true
   */
  showConnectors?: boolean;

  /**
   * Compact mode
   * @default false
   */
  compact?: boolean;
}

/**
 * ActivityFeed Component Styles
 *
 * Optimized for Product Mode (SaaS dashboards).
 * Timeline layout with efficient information scanning.
 */

.activityFeed {
  display: flex;
  flex-direction: column;
  gap: var(--spacing-4);
}

/* ============================================================================
 * FILTERS
 * ============================================================================ */

.filters {
  display: flex;
  gap: var(--spacing-2);
  flex-wrap: wrap;
  padding-bottom: var(--spacing-4);
  border-bottom: 1px solid var(--border-subtle);
}

/* ============================================================================
 * LIST
 * ============================================================================ */

.list {
  display: flex;
  flex-direction: column;
}

.empty {
  padding: var(--spacing-8);
  text-align: center;
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  color: var(--text-tertiary);
}

/* ============================================================================
 * ITEM
 * ============================================================================ */

.item {
  display: flex;
  align-items: flex-start;
  gap: var(--spacing-3);
  padding: var(--spacing-4) 0;
}

.item:first-child {
  padding-top: 0;
}

.itemCompact {
  padding: var(--spacing-2-5) 0;
}

.itemCompact:first-child {
  padding-top: 0;
}

/* Icon column */
.iconColumn {
  display: flex;
  flex-direction: column;
  align-items: center;
  flex-shrink: 0;
}

.iconWrapper {
  display: flex;
  align-items: center;
  justify-content: center;
  width: var(--size-icon-xl);
  height: var(--size-icon-xl);
  border-radius: var(--radius-full);
  background: var(--surface-subtle);
  color: var(--text-secondary);
  flex-shrink: 0;
}

.iconVariant-success {
  background: var(--status-success-bg);
  color: var(--text-success);
}

.iconVariant-warning {
  background: var(--status-warning-bg);
  color: var(--text-warning);
}

.iconVariant-error {
  background: var(--status-error-bg);
  color: var(--text-error);
}

.iconVariant-info {
  background: var(--status-info-bg);
  color: var(--text-info);
}

.iconVariant-brand {
  background: var(--interactive-primary);
  color: var(--interactive-primary-text);
}

.connector {
  width: var(--border-width-bold);
  flex: 1;
  min-height: var(--size-icon-sm);
  background: var(--border-subtle);
  margin-top: var(--spacing-2);
}

/* Content */
.content {
  flex: 1;
  min-width: 0;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
}

.header {
  display: flex;
  align-items: center;
  gap: var(--spacing-2);
  font-family: var(--font-secondary);
  font-size: var(--font-size-14);
  line-height: var(--line-height-tight);
  min-height: var(--size-icon-xl);
}

.actor {
  display: inline-flex;
  align-items: center;
  gap: var(--spacing-2);
  flex-shrink: 0;
}

.avatar {
  width: var(--size-avatar-xs);
  height: var(--size-avatar-xs);
  border-radius: var(--radius-full);
  object-fit: cover;
  flex-shrink: 0;
}

.actorName {
  font-weight: 600;
  color: var(--text-primary);
  text-decoration: none;
  white-space: nowrap;
}

a.actorName:hover {
  text-decoration: underline;
}

.title {
  color: var(--text-primary);
  flex: 1;
  min-width: 0;
}

.time {
  color: var(--text-tertiary);
  font-size: var(--font-size-12);
  white-space: nowrap;
  flex-shrink: 0;
  margin-left: var(--spacing-2);
}

.description {
  font-family: var(--font-secondary);
  font-size: var(--font-size-13);
  color: var(--text-secondary);
  line-height: var(--line-height-relaxed);
  padding: var(--spacing-2) var(--spacing-3);
  background: var(--surface-subtle);
  border-radius: var(--radius-sm);
}

.metadata {
  display: flex;
  flex-wrap: wrap;
  gap: var(--spacing-3);
}

.metadataItem {
  display: inline-flex;
  gap: var(--spacing-1);
  font-family: var(--font-secondary);
  font-size: var(--font-size-12);
}

.metadataKey {
  color: var(--text-tertiary);
}

.metadataValue {
  color: var(--text-secondary);
}

.actions {
  display: flex;
  gap: var(--spacing-2);
  margin-top: var(--spacing-2);
}

/* ============================================================================
 * COMPACT MODE
 * ============================================================================ */

.compact .item {
  gap: var(--spacing-2);
}

.compact .iconWrapper {
  width: var(--size-icon-lg);
  height: var(--size-icon-lg);
}

.compact .content {
  gap: var(--spacing-1-5);
}

.compact .header {
  font-size: var(--font-size-13);
  min-height: var(--size-icon-lg);
  gap: var(--spacing-2);
}

.compact .actor {
  gap: var(--spacing-2);
}

.compact .description {
  font-size: var(--font-size-12);
  padding: var(--spacing-1-5) var(--spacing-2);
}

/* ============================================================================
 * LOADING SKELETON
 * ============================================================================ */

.skeleton {
  display: flex;
  gap: var(--spacing-3);
  padding: var(--spacing-3) 0;
}

.skeletonIcon {
  width: var(--size-icon-xl);
  height: var(--size-icon-xl);
  border-radius: var(--radius-full);
  background: var(--surface-subtle);
  animation: pulse 1.5s ease-in-out infinite;
}

.skeletonContent {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: var(--spacing-2);
}

.skeletonTitle {
  width: 60%;
  height: var(--size-icon-sm);
  border-radius: var(--radius-sm);
  background: var(--surface-subtle);
  animation: pulse 1.5s ease-in-out infinite;
}

.skeletonDesc {
  width: 80%;
  height: var(--font-size-12);
  border-radius: var(--radius-sm);
  background: var(--surface-subtle);
  animation: pulse 1.5s ease-in-out infinite;
}

@keyframes pulse {
  0%,
  100% {
    opacity: 1;
  }
  50% {
    opacity: 0.5;
  }
}

/* ============================================================================
 * LOAD MORE
 * ============================================================================ */
/* Removed - Now uses Orion Button component */

export { ActivityFeed } from "./ActivityFeed";
export type {
  ActivityFeedProps,
  ActivityItem,
  ActivityActor,
  ActivityFilter,
} from "./ActivityFeed.types";
